local function CanCast(self, doer, target, pos, ...) return(not self:GetCooldownPercent() or self:GetCooldownPercent() == 0x1) and self.dycOldCanCast(self, doer, target, pos, ...) end local function CastSpell(self, target, pos, ...) if self.dycCooldown and self.dycCooldown > 0x0 then self.dycCooldownCurrent = self.dycCooldown self.inst:StartUpdatingComponent(self) end return self.dycOldCastSpell(self, target, pos, ...) end local function OnUpdate(self, dt, ...) dt = TheSim:GetTickTime() * TheSim:GetTimeScale() local current, max = self.dycCooldownCurrent, self.dycCooldown if current and max and current > 0x0 then current = math.max(current - dt, 0x0) self.dycCooldownCurrent = current self.inst:PushEvent( "cooldownchange" , {percent = self:GetCooldownPercent()}) end if self.dycOldOnUpdate then return self.dycOldOnUpdate(self, dt, ...) end end local function GetCooldownPercent(self) if self.dycCooldown and self.dycCooldown > 0x0 and self.dycCooldownCurrent then return 0x1 - math.max(0x0, math.min(self.dycCooldownCurrent / self.dycCooldown, 0x1)) end end local function SetCastFXPrefab(self, pf) self.dycCastFXPrefab = pf end local function SpawnCastFX(self, pos, rot) local fx = SpawnPrefab(self.dycCastFXPrefab or "staffcastfx" ) fx.Transform:SetPosition(pos.x, pos.y, pos.z) fx.Transform:SetRotation(rot) if self.onspawncastfx then self.onspawncastfx(self.inst, fx, pos, rot) end return fx end local function OnChannelStart(self, caster, target, pos) if self.onchannelstart then self.onchannelstart(self.inst, caster, target, pos) end end local function OnChannelEnd(self, caster, target, pos) if self.onchannelend then self.onchannelend(self.inst, caster, target, pos) end end local function SetOnSpawnCastFXFn(self, fn) self.onspawncastfx = fn end local function SetOnChannelStartFn(self, fn) self.onchannelstart = fn end local function SetOnChannelEndFn(self, fn) self.onchannelend = fn end local function InitCooldown(self, cd) self.dycCooldown = cd or 0x0 self.dycCooldownCurrent = 0x0 end local function SetAOEUI(self, range, pf, k) self.dycAOERange = range or 0x0 self.dycAOEPrefab = pf or "dyc_fx_aoering" self.dycAOEK = k or 0.375 end local function DYCSpellCaster(self) self.dycOldCastSpell = self.CastSpell self.CastSpell = CastSpell self.dycOldCanCast = self.CanCast self.CanCast = CanCast self.dycOldOnUpdate = self.OnUpdate self.OnUpdate = OnUpdate self.GetCooldownPercent = GetCooldownPercent self.InitCooldown = InitCooldown self.SpawnCastFX = SpawnCastFX self.SetCastFXPrefab = SetCastFXPrefab self.OnChannelStart = OnChannelStart self.OnChannelEnd = OnChannelEnd self.SetOnChannelStartFn = SetOnChannelStartFn self.SetOnChannelEndFn = SetOnChannelEndFn self.SetOnSpawnCastFXFn = SetOnSpawnCastFXFn self.SetAOEUI = SetAOEUI self.dycCooldown = 0x0 self.dycCooldownCurrent = 0x0 end return DYCSpellCaster 